     1→use sqlx::postgres::{PgConnectOptions, PgSslMode};
     2→
     3→#[derive(serde::Deserialize, Clone)]
     4→pub struct Settings {
     5→    pub application: ApplicationSettings,
     6→    pub database: DatabaseSettings,
     7→}
     8→
     9→#[derive(serde::Deserialize, Clone)]
    10→pub struct ApplicationSettings {
    11→    pub host: String,
    12→    pub port: u16,
    13→}
    14→
    15→#[derive(serde::Deserialize, Clone)]
    16→pub struct DatabaseSettings {
    17→    pub host: String,
    18→    pub port: u16,
    19→    pub username: String,
    20→    pub password: String,
    21→    pub database_name: String,
    22→    pub require_ssl: bool,
    23→}
    24→
    25→impl DatabaseSettings {
    26→    pub fn connect_options(&self) -> PgConnectOptions {
    27→        let ssl_mode = if self.require_ssl {
    28→            PgSslMode::Require
    29→        } else {
    30→            PgSslMode::Prefer
    31→        };
    32→        PgConnectOptions::new()
    33→            .host(&self.host)
    34→            .port(self.port)
    35→            .username(&self.username)
    36→            .password(&self.password)
    37→            .database(&self.database_name)
    38→            .ssl_mode(ssl_mode)
    39→    }
    40→
    41→    pub fn connect_options_without_db(&self) -> PgConnectOptions {
    42→        let ssl_mode = if self.require_ssl {
    43→            PgSslMode::Require
    44→        } else {
    45→            PgSslMode::Prefer
    46→        };
    47→        PgConnectOptions::new()
    48→            .host(&self.host)
    49→            .port(self.port)
    50→            .username(&self.username)
    51→            .password(&self.password)
    52→            .ssl_mode(ssl_mode)
    53→    }
    54→}
    55→
    56→pub fn get_configuration() -> Result<Settings, config::ConfigError> {
    57→    let config = config::Config::builder()
    58→        .add_source(config::File::with_name("config/base"))
    59→        .add_source(config::File::with_name("config/local").required(false))
    60→        .add_source(
    61→            config::Environment::with_prefix("APP")
    62→                .separator("__")
    63→                .try_parsing(true),
    64→        )
    65→        .build()?;
    66→
    67→    config.try_deserialize()
    68→}
