     1→use axum::Router;
     2→use sqlx::postgres::PgPoolOptions;
     3→use sqlx::PgPool;
     4→use tokio::net::TcpListener;
     5→use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
     6→use tower_http::services::ServeDir;
     7→use tower_http::trace::TraceLayer;
     8→use tower_sessions::SessionManagerLayer;
     9→use tower_sessions_sqlx_store::PostgresStore;
    10→
    11→use crate::configuration::Settings;
    12→use crate::routes::{
    13→    get_edit_todo, get_forgot_password, get_login, get_register, get_todo_item, get_todos_page,
    14→    health_check, index, post_delete_todo, post_edit_todo, post_login, post_logout, post_register,
    15→    post_todo, post_toggle_todo,
    16→};
    17→
    18→pub struct Application {
    19→    listener: TcpListener,
    20→    pool: PgPool,
    21→}
    22→
    23→impl Application {
    24→    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
    25→        let pool = PgPoolOptions::new()
    26→            .max_connections(5)
    27→            .connect_with(settings.database.connect_options())
    28→            .await?;
    29→
    30→        sqlx::migrate!("./migrations").run(&pool).await?;
    31→
    32→        let session_store = PostgresStore::new(pool.clone());
    33→        session_store.migrate().await?;
    34→
    35→        let address = format!(
    36→            "{}:{}",
    37→            settings.application.host, settings.application.port
    38→        );
    39→        let listener = TcpListener::bind(&address).await?;
    40→
    41→        tracing::info!("Listening on {}", listener.local_addr()?);
    42→
    43→        Ok(Self { listener, pool })
    44→    }
    45→
    46→    pub fn port(&self) -> u16 {
    47→        self.listener.local_addr().unwrap().port()
    48→    }
    49→
    50→    pub fn router(pool: PgPool) -> Router {
    51→        let x_request_id = axum::http::HeaderName::from_static("x-request-id");
    52→
    53→        let session_store = PostgresStore::new(pool.clone());
    54→        let session_layer = SessionManagerLayer::new(session_store);
    55→
    56→        Router::new()
    57→            .route("/", axum::routing::get(index))
    58→            .route(
    59→                "/register",
    60→                axum::routing::get(get_register).post(post_register),
    61→            )
    62→            .route("/login", axum::routing::get(get_login).post(post_login))
    63→            .route("/forgot-password", axum::routing::get(get_forgot_password))
    64→            .route("/logout", axum::routing::post(post_logout))
    65→            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
    66→            .route("/todos/{id}", axum::routing::get(get_todo_item))
    67→            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
    68→            .route("/todos/{id}/delete", axum::routing::post(post_delete_todo))
    69→            .route(
    70→                "/todos/{id}/edit",
    71→                axum::routing::get(get_edit_todo).post(post_edit_todo),
    72→            )
    73→            .route("/health_check", axum::routing::get(health_check))
    74→            .nest_service("/static", ServeDir::new("static"))
    75→            .layer(session_layer)
    76→            .layer(TraceLayer::new_for_http())
    77→            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
    78→            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
    79→            .with_state(pool)
    80→    }
    81→
    82→    pub async fn run(self) -> Result<(), std::io::Error> {
    83→        let router = Self::router(self.pool);
    84→        axum::serve(self.listener, router).await
    85→    }
    86→}
